class InventoryManager:
    """Manages all inventory operations with concurrency-safe locks."""

    def __init__(self):
        self._player_locks: Dict[str, asyncio.Lock] = {}
        self._trade_lock = asyncio.Lock()
        self._global_item_lock = asyncio.Lock()

    def get_player_lock(self, player_id: str) -> asyncio.Lock:
        if player_id not in self._player_locks:
            self._player_locks[player_id] = asyncio.Lock()
        return self._player_locks[player_id]

    async def acquire_player_locks(self, *player_ids: str):
        """Acquire multiple player locks in a consistent order to prevent deadlocks."""
        sorted_ids = sorted(player_ids)
        locks = [self.get_player_lock(pid) for pid in sorted_ids]
        for lock in locks:
            await lock.acquire()
        return locks

    def release_player_locks(self, locks: list):
        for lock in locks:
            lock.release()

    async def add_item_to_player(self, player: Player, item: Item) -> bool:
        lock = self.get_player_lock(player.player_id)
        async with lock:
            if len(player.inventory) >= player.max_inventory_size:
                return False
            item.owner_id = player.player_id
            player.inventory[item.item_id] = item
            return True

    async def remove_item_from_player(self, player: Player, item_id: str) -> Optional[Item]:
        lock = self.get_player_lock(player.player_id)
        async with lock:
            if item_id in player.inventory:
                item = player.inventory.pop(item_id)
                item.owner_id = None
                return item
            return None

    async def transfer_item(self, from_player: Player, to_player: Player, item_id: str) -> bool:
        """Transfer a single item between players atomically."""
        locks = await self.acquire_player_locks(from_player.player_id, to_player.player_id)
        try:
            if item_id not in from_player.inventory:
                logger.warning(f"Item {item_id} not found in {from_player.username}'s inventory")
                return False

            item = from_player.inventory[item_id]

            if not item.tradeable:
                logger.warning(f"Item {item_id} is not tradeable")
                return False

            if len(to_player.inventory) >= to_player.max_inventory_size:
                logger.warning(f"{to_player.username}'s inventory is full")
                return False

            del from_player.inventory[item_id]
            item.owner_id = to_player.player_id
            to_player.inventory[item_id] = item

            logger.info(
                f"Transferred item '{item.name}' ({item_id}) "
                f"from {from_player.username} to {to_player.username}"
            )
            return True
        finally:
            self.release_player_locks(locks)

    async def transfer_gold(self, from_player: Player, to_player: Player, amount: int) -> bool:
        """Transfer gold between players atomically."""
        if amount <= 0:
            return False

        locks = await self.acquire_player_locks(from_player.player_id, to_player.player_id)
        try:
            if from_player.gold < amount:
                logger.warning(f"{from_player.username} doesn't have enough gold ({from_player.gold} < {amount})")
                return False

            from_player.gold -= amount
            to_player.gold += amount

            logger.info(
                f"Transferred {amount} gold from {from_player.username} to {to_player.username}"
            )
            return True
        finally:
            self.release_player_locks(locks)


class TradeManager:
    """Manages trade sessions between players."""

    def __init__(self, inventory_manager: InventoryManager):
        self.trades: Dict[str, TradeOffer] = {}
        self.inventory_manager = inventory_manager
        self._trade_lock = asyncio.Lock()

    async def create_trade(self, initiator: Player, target: Player) -> Optional[TradeOffer]:
        async with self._trade_lock:
            if initiator.active_trade_id is not None:
                logger.warning(f"{initiator.username} is already in a trade")
                return None
            if target.active_trade_id is not None:
                logger.warning(f"{target.username} is already in a trade")
                return None

            trade_id = str(uuid.uuid4())
            trade = TradeOffer(
                trade_id=trade_id,
                initiator_id=initiator.player_id,
                target_id=target.player_id,
            )
            self.trades[trade_id] = trade
            initiator.active_trade_id = trade_id
            target.active_trade_id = trade_id

            logger.info(f"Trade {trade_id} created between {initiator.username} and {target.username}")
            return trade

    async def add_item_to_trade(
        self, trade_id: str, player_id: str, item_id: str, players: Dict[str, Player]
    ) -> bool:
        async with self._trade_lock:
            if trade_id not in self.trades:
                return False

            trade = self.trades[trade_id]
            if trade.status != "pending":
                return False

            # Reset acceptances when trade is modified
            trade.initiator_accepted = False
            trade.target_accepted = False

            player = players.get(player_id)
            if player is None:
                return False

            if item_id not in player.inventory:
                return False

            item = player.inventory[item_id]
            if not item.tradeable:
                return False

            if player_id == trade.initiator_id:
                if item_id not in trade.initiator_items:
                    trade.initiator_items.append(item_id)
            elif player_id == trade.target_id:
                if item_id not in trade.target_items:
                    trade.target_items.append(item_id)
            else:
                return False

            logger.info(f"Item {item_id} added to trade {trade_id} by player {player_id}")
            return True

    async def remove_item_from_trade(
        self, trade_id: str, player_id: str, item_id: str
    ) -> bool:
        async with self._trade_lock:
            if trade_id not in self.trades:
                return False

            trade = self.trades[trade_id]
            if trade.status != "pending":
                return False

            # Reset acceptances when trade is modified
            trade.initiator_accepted = False
            trade.target_accepted = False

            if player_id == trade.initiator_id:
                if item_id in trade.initiator_items:
                    trade.initiator_items.remove(item_id)
                    return True
            elif player_id == trade.target_id:
                if item_id in trade.target_items:
                    trade.target_items.remove(item_id)
                    return True
            return False

    async def set_gold_offer(
        self, trade_id: str, player_id: str, amount: int, players: Dict[str, Player]
    ) -> bool:
        async with self._trade_lock:
            if trade_id not in self.trades:
                return False

            trade = self.trades[trade_id]
            if trade.status != "pending":
                return False

            if amount < 0:
                return False

            player = players.get(player_id)
            if player is None or player.gold < amount:
                return False

            # Reset acceptances when trade is modified
            trade.initiator_accepted = False
            trade.target_accepted = False

            if player_id == trade.initiator_id:
                trade.initiator_gold = amount
            elif player_id == trade.target_id:
                trade.target_gold = amount
            else:
                return False

            return True

    async def accept_trade(
        self, trade_id: str, player_id: str, players: Dict[str, Player]
    ) -> Optional[str]:
        """
        Returns: 'waiting' if one side accepted, 'completed' if both accepted,
                 None on failure.
        """
        async with self._trade_lock:
            if trade_id not in self.trades:
                return None

            trade = self.trades[trade_id]
            if trade.status != "pending":
                return None

            if player_id == trade.initiator_id:
                trade.initiator_accepted = True
            elif player_id == trade.target_id:
                trade.target_accepted = True
            else:
                return None

            if trade.initiator_accepted and trade.target_accepted:
                trade.status = "accepted"
                # Execute the trade outside the lock context
                # but mark it so no one else can modify
                pass
            else:
                return "waiting"

        # If both accepted, execute the trade
        if trade.status == "accepted":
            success = await self._execute_trade(trade, players)
            if success:
                await self._cleanup_trade(trade_id, players)
                return "completed"
            else:
                async with self._trade_lock:
                    trade.status = "pending"
                    trade.initiator_accepted = False
                    trade.target_accepted = False
                return None

        return "waiting"

    async def _execute_trade(self, trade: TradeOffer, players: Dict[str, Player]) -> bool:
        """Execute the actual item and gold transfers atomically."""
        initiator = players.get(trade.initiator_id)
        target = players.get(trade.target_id)

        if not initiator or not target:
            return False

        # Acquire locks for both players in consistent order
        locks = await self.inventory_manager.acquire_player_locks(
            initiator.player_id, target.player_id
        )

        try:
            # Validate all items still exist and are tradeable
            for item_id in trade.initiator_items:
                if item_id not in initiator.inventory:
                    logger.warning(f"Trade validation failed: item {item_id} not in initiator inventory")
                    return False
                if not initiator.inventory[item_id].tradeable:
                    logger.warning(f"Trade validation failed: item {item_id} not tradeable")
                    return False

            for item_id in trade.target_items:
                if item_id not in target.inventory:
                    logger.warning(f"Trade validation failed: item {item_id} not in target inventory")
                    return False
                if not target.inventory[item_id].tradeable:
                    logger.warning(f"Trade validation failed: item {item_id} not tradeable")
                    return False

            # Validate gold
            if initiator.gold < trade.initiator_gold:
                logger.warning(f"Trade validation failed: initiator doesn't have enough gold")
                return False
            if target.gold < trade.target_gold:
                logger.warning(f"Trade validation failed: target doesn't have enough gold")
                return False

            # Validate inventory space
            initiator_net_items = len(trade.target_items) - len(trade.initiator_items)
            target_net_items = len(trade.initiator_items) - len(trade.target_items)

            if len(initiator.inventory) + initiator_net_items > initiator.max_inventory_size:
                logger.warning(f"Trade validation failed: initiator inventory would overflow")
                return False
            if len(target.inventory) + target_net_items > target.max_inventory_size:
                logger.warning(f"Trade validation failed: target inventory would overflow")
                return False

            # Execute transfers atomically (we already hold both locks)
            # Transfer items from initiator to target
            for item_id in trade.initiator_items:
                item = initiator.inventory.pop(item_id)
                item.owner_id = target.player_id
                target.inventory[item_id] = item

            # Transfer items from target to initiator
            for item_id in trade.target_items:
                item = target.inventory.pop(item_id)
                item.owner_id = initiator.player_id
                initiator.inventory[item_id] = item

            # Transfer gold
            if trade.initiator_gold > 0:
                initiator.gold -= trade.initiator_gold
                target.gold += trade.initiator_gold

            if trade.target_gold > 0:
                target.gold -= trade.target_gold
                initiator.gold += trade.target_gold

            logger.info(
                f"Trade {trade.trade_id} executed successfully: "
                f"{len(trade.initiator_items)} items + {trade.initiator_gold}g from {initiator.username}, "
                f"{len(trade.target_items)} items + {trade.target_gold}g from {target.username}"
            )
            return True

        except Exception as e:
            logger.error(f"Trade execution failed: {e}")
            return False
        finally:
            self.inventory_manager.release_player_locks(locks)

    async def cancel_trade(self, trade_id: str, player_id: str, players: Dict[str, Player]) -> bool:
        async with self._trade_lock:
            if trade_id not in self.trades:
                return False

            trade = self.trades[trade_id]
            if trade.status not in ("pending", "accepted"):
                return False

            if player_id not in (trade.initiator_id, trade.target_id):
                return False

            trade.status = "cancelled"

        await self._cleanup_trade(trade_id, players)
        logger.info(f"Trade {trade_id} cancelled by {player_id}")
        return True

    async def _cleanup_trade(self, trade_id: str, players: Dict[str, Player]):
        async with self._trade_lock:
            trade = self.trades.get(trade_id)
            if trade:
                initiator = players.get(trade.initiator_id)
                target = players.get(trade.target_id)
                if initiator and initiator.active_trade_id == trade_id:
                    initiator.active_trade_id = None
                if target and target.active_trade_id == trade_id:
                    target.active_trade_id = None
                del self.trades[trade_id]


class ItemDatabase:
    """Template items that can be spawned into the game."""

    TEMPLATES = {
        "iron_sword": {"name": "Iron Sword", "rarity": ItemRarity.COMMON, "base_value": 50},
        "steel_shield": {"name": "Steel Shield", "rarity": ItemRarity.COMMON, "base_value": 75},
        "health_potion": {"name": "Health Potion", "rarity": ItemRarity.COMMON, "base_value": 25},
        "mana_potion": {"name": "Mana Potion", "rarity": ItemRarity.COMMON, "base_value": 30},
        "elven_bow": {"name": "Elven Bow", "rarity": ItemRarity.UNCOMMON, "base_value": 150},
        "magic_staff": {"name": "Magic Staff", "rarity": ItemRarity.RARE, "base_value": 300},
        "dragon_armor": {"name": "Dragon Armor", "rarity": ItemRarity.EPIC, "base_value": 1000},
        "excalibur": {"name": "Excalibur", "rarity": ItemRarity.LEGENDARY, "base_value": 5000, "tradeable": False},
        "golden_ring": {"name": "Golden Ring", "rarity": ItemRarity.UNCOMMON, "base_value": 200},
        "phoenix_feather": {"name": "Phoenix Feather", "rarity": ItemRarity.RARE, "base_value": 500},
    }

    @classmethod
    def create_item(cls, template_id: str) -> Optional[Item]:
        if template_id not in cls.TEMPLATES:
            return None
        template = cls.TEMPLATES[template_id]
        return Item(
            item_id=str(uuid.uuid4()),
            name=template["name"],
            rarity=template["rarity"],
            base_value=template.get("base_value", 0),
            tradeable=template.get("tradeable", True),
        )


class GameServer:
    def __init__(self, host: str = "localhost", port: int = 8765):
        self.host = host
        self.port = port
        self.players: Dict[str, Player] = {}
        self.connections: Dict[str, websockets.WebSocketServerProtocol] = {}
        self.username_to_id: Dict[str, str] = {}
        self.inventory_manager = InventoryManager()
        self.trade_manager = TradeManager(self.inventory_manager)
        self._connection_lock = asyncio.Lock()

    async def send_to_player(self, player_id: str, message: dict):
        if player_id in self.connections:
            try:
                await self.connections[player_id].send(json.dumps(message))
            except websockets.exceptions.ConnectionClosed:
                logger.warning(f"Failed to send message to {player_id}: connection closed")

    async def broadcast(self, message: dict, exclude: Optional[Set[str]] = None):
        exclude = exclude or set()
        tasks = []
        for pid, ws in self.connections.items():
            if pid not in exclude:
                tasks.append(self.send_to_player(pid, message))
        await asyncio.gather(*tasks, return_exceptions=True)

    async def handle_login(self, websocket, data: dict) -> Optional[str]:
        username = data.get("username", "").strip()
        if not username:
            await websocket.send(json.dumps({
                "type": "error",
                "message": "Username is required"
            }))
            return None

        async with self._connection_lock:
            if username in self.username_to_id:
                await websocket.send(json.dumps({
                    "type": "error",
                    "message": f"Username '{username}' is already taken"
                }))
                return None

            player_id = str(uuid.uuid4())
            player = Player(
                player_id=player_id,
                username=username,
                websocket=websocket,
            )

            # Give starter items
            starter_items = ["iron_sword", "health_potion", "health_potion", "mana_potion"]
            for template_id in starter_items:
                item = ItemDatabase.create_item(template_id)
                if item:
                    item.owner_id = player_id
                    player.inventory[item.item_id] = item

            self.players[player_id] = player
            self.connections[player_id] = websocket
            self.username_to_id[username] = player_id

        await websocket.send(json.dumps({
            "type": "login_success",
            "player": player.to_dict(),
        }))

        await self.broadcast({
            "type": "player_joined",
            "username": username,
            "player_id": player_id,
            "online_players": [
                {"player_id": p.player_id, "username": p.username}
                for p in self.players.values()
            ],
        }, exclude={player_id})

        logger.info(f"Player '{username}' ({player_id}) logged in")
        return player_id

    async def handle_disconnect(self, player_id: str):
        async with self._connection_lock:
            if player_id not in self.players:
                return

            player = self.players[player_id]

            # Cancel any active trade
            if player.active_trade_id:
                trade = self.trade_manager.trades.get(player.active_trade_id)
                if trade:
                    other_id = (
                        trade.target_id if trade.initiator_id == player_id
                        else trade.initiator_id
                    )
                    await self.trade_manager.cancel_trade(
                        player.active_trade_id, player_id, self.players
                    )
                    await self.send_to_player(other_id, {
                        "type": "trade_cancelled",
                        "reason": f"{player.username} disconnected",
                    })

            username = player.username
            del self.players[player_id]
            del self.connections[player_id]
            if username in self.username_to_id:
                del self.username_to_id[username]

        await self.broadcast({
            "type": "player_left",
            "username": username,
            "player_id": player_id,
        })

        logger.info(f"Player '{username}' ({player_id}) disconnected")

    async def handle_get_inventory(self, player_id: str):
        player = self.players.get(player_id)
        if not player:
            return

        await self.send_to_player(player_id, {
            "type": "inventory",
            "inventory": {k: v.to_dict() for k, v in player.inventory.items()},
            "gold": player.gold,
            "slots_used": len(player.inventory),
            "max_slots": player.max_inventory_size,
        })

    async def handle_spawn_item(self, player_id: str, data: dict):
        """Debug/admin command to spawn items."""
        template_id = data.get("template_id")
        if not template_id:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": "template_id is required",
            })
            return

        item = ItemDatabase.create_item(template_id)
        if not item:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": f"Unknown item template: {template_id}",
            })
            return

        player = self.players.get(player_id)
        if not player:
            return

        success = await self.inventory_manager.add_item_to_player(player, item)
        if success:
            await self.send_to_player(player_id, {
                "type": "item_received",
                "item": item.to_dict(),
                "message": f"Received {item.name}!",
            })
        else:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": "Inventory is full!",
            })

    async def handle_drop_item(self, player_id: str, data: dict):
        item_id = data.get("item_id")
        if not item_id:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": "item_id is required",
            })
            return

        player = self.players.get(player_id)
        if not player:
            return

        item = await self.inventory_manager.remove_item_from_player(player, item_id)
        if item:
            await self.send_to_player(player_id, {
                "type": "item_dropped",
                "item": item.to_dict(),
                "message": f"Dropped {item.name}",
            })
        else:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": "Item not found in inventory",
            })

    async def handle_gift_item(self, player_id: str, data: dict):
        """Direct item transfer (gift) without trade UI."""
        item_id = data.get("item_id")
        target_username = data.get("target_username")

        if not item_id or not target_username:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": "item_id and target_username are required",
            })
            return

        target_id = self.username_to_id.get(target_username)
        if not target_id:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": f"Player '{target_username}' not found",
            })
            return

        if target_id == player_id:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": "Cannot gift items to yourself",
            })
            return

        from_player = self.players.get(player_id)
        to_player = self.players.get(target_id)

        if not from_player or not to_player:
            return

        success = await self.inventory_manager.transfer_item(from_player, to_player, item_id)
        if success:
            item = to_player.inventory[item_id]
            await self.send_to_player(player_id, {
                "type": "item_gifted",
                "item": item.to_dict(),
                "to_player": target_username,
                "message": f"Gifted {item.name} to {target_username}",
            })
            await self.send_to_player(target_id, {
                "type": "item_received",
                "item": item.to_dict(),
                "from_player": from_player.username,
                "message": f"Received {item.name} from {from_player.username}!",
            })
        else:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": "Failed to gift item (not found, not tradeable, or target inventory full)",
            })

    async def handle_trade_request(self, player_id: str, data: dict):
        target_username = data.get("target_username")
        if not target_username:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": "target_username is required",
            })
            return

        target_id = self.username_to_id.get(target_username)
        if not target_id:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": f"Player '{target_username}' not found",
            })
            return

        if target_id == player_id:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": "Cannot trade with yourself",
            })
            return

        initiator = self.players.get(player_id)
        target = self.players.get(target_id)

        if not initiator or not target:
            return

        trade = await self.trade_manager.create_trade(initiator, target)
        if trade:
            await self.send_to_player(player_id, {
                "type": "trade_started",
                "trade": trade.to_dict(),
                "role": "initiator",
                "message": f"Trade started with {target_username}",
            })
            await self.send_to_player(target_id, {
                "type": "trade_request",
                "trade": trade.to_dict(),
                "role": "target",
                "from_player": initiator.username,
                "message": f"{initiator.username} wants to trade with you!",
            })
        else:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": "Cannot start trade (you or target already in a trade)",
            })

    async def handle_trade_add_item(self, player_id: str, data: dict):
        player = self.players.get(player_id)
        if not player or not player.active_trade_id:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": "Not in an active trade",
            })
            return

        item_id = data.get("item_id")
        if not item_id:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": "item_id is required",
            })
            return

        trade_id = player.active_trade_id
        success = await self.trade_manager.add_item_to_trade(
            trade_id, player_id, item_id, self.players
        )

        trade = self.trade_manager.trades.get(trade_id)
        if success and trade:
            other_id = (
                trade.target_id if trade.initiator_id == player_id
                else trade.initiator_id
            )
            trade_update = {
                "type": "trade_updated",
                "trade": trade.to_dict(),
            }
            await self.send_to_player(player_id, trade_update)
            await self.send_to_player(other_id, trade_update)
        else:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": "Failed to add item to trade",
            })

    async def handle_trade_remove_item(self, player_id: str, data: dict):
        player = self.players.get(player_id)
        if not player or not player.active_trade_id:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": "Not in an active trade",
            })
            return

        item_id = data.get("item_id")
        if not item_id:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": "item_id is required",
            })
            return

        trade_id = player.active_trade_id
        success = await self.trade_manager.remove_item_from_trade(
            trade_id, player_id, item_id
        )

        trade = self.trade_manager.trades.get(trade_id)
        if success and trade:
            other_id = (
                trade.target_id if trade.initiator_id == player_id
                else trade.initiator_id
            )
            trade_update = {
                "type": "trade_updated",
                "trade": trade.to_dict(),
            }
            await self.send_to_player(player_id, trade_update)
            await self.send_to_player(other_id, trade_update)
        else:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": "Failed to remove item from trade",
            })

    async def handle_trade_set_gold(self, player_id: str, data: dict):
        player = self.players.get(player_id)
        if not player or not player.active_trade_id:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": "Not in an active trade",
            })
            return

        amount = data.get("amount", 0)
        if not isinstance(amount, int) or amount < 0:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": "Invalid gold amount",
            })
            return

        trade_id = player.active_trade_id
        success = await self.trade_manager.set_gold_offer(
            trade_id, player_id, amount, self.players
        )

        trade = self.trade_manager.trades.get(trade_id)
        if success and trade:
            other_id = (
                trade.target_id if trade.initiator_id == player_id
                else trade.initiator_id
            )
            trade_update = {
                "type": "trade_updated",
                "trade": trade.to_dict(),
            }
            await self.send_to_player(player_id, trade_update)
            await self.send_to_player(other_id, trade_update)
        else:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": "Failed to set gold amount (insufficient gold or invalid trade)",
            })

    async def handle_trade_accept(self, player_id: str, data: dict):
        player = self.players.get(player_id)
        if not player or not player.active_trade_id:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": "Not in an active trade",
            })
            return

        trade_id = player.active_trade_id
        trade = self.trade_manager.trades.get(trade_id)
        if not trade:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": "Trade not found",
            })
            return

        other_id = (
            trade.target_id if trade.initiator_id == player_id
            else trade.initiator_id
        )

        result = await self.trade_manager.accept_trade(trade_id, player_id, self.players)

        if result == "waiting":
            await self.send_to_player(player_id, {
                "type": "trade_accepted_waiting",
                "message": "You accepted the trade. Waiting for the other player...",
                "trade": trade.to_dict(),
            })
            await self.send_to_player(other_id, {
                "type": "trade_partner_accepted",
                "message": f"{player.username} accepted the trade!",
                "trade": trade.to_dict(),
            })
        elif result == "completed":
            initiator = self.players.get(trade.initiator_id)
            target = self.players.get(trade.target_id)

            for pid in (trade.initiator_id, trade.target_id):
                p = self.players.get(pid)
                if p:
                    await self.send_to_player(pid, {
                        "type": "trade_completed",
                        "message": "Trade completed successfully!",
                        "inventory": {k: v.to_dict() for k, v in p.inventory.items()},
                        "gold": p.gold,
                    })
        else:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": "Trade failed - items may have changed. Please try again.",
            })
            # Notify both players
            for pid in (trade.initiator_id, trade.target_id):
                t = self.trade_manager.trades.get(trade_id)
                if t:
                    await self.send_to_player(pid, {
                        "type": "trade_updated",
                        "trade": t.to_dict(),
                        "message": "Trade acceptance was reset due to a validation error.",
                    })

    async def handle_trade_cancel(self, player_id: str, data: dict):
        player = self.players.get(player_id)
        if not player or not player.active_trade_id:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": "Not in an active trade",
            })
            return

        trade_id = player.active_trade_id
        trade = self.trade_manager.trades.get(trade_id)
        if not trade:
            return

        other_id = (
            trade.target_id if trade.initiator_id == player_id
            else trade.initiator_id
        )

        success = await self.trade_manager.cancel_trade(trade_id, player_id, self.players)
        if success:
            await self.send_to_player(player_id, {
                "type": "trade_cancelled",
                "message": "Trade cancelled",
            })
            await self.send_to_player(other_id, {
                "type": "trade_cancelled",
                "message": f"{player.username} cancelled the trade",
            })

    async def handle_list_players(self, player_id: str):
        players_list = [
            {
                "player_id": p.player_id,
                "username": p.username,
                "in_trade": p.active_trade_id is not None,
            }
            for p in self.players.values()
        ]
        await self.send_to_player(player_id, {
            "type": "player_list",
            "players": players_list,
        })

    async def handle_inspect_player(self, player_id: str, data: dict):
        """View another player's public inventory info."""
        target_username = data.get("target_username")
        if not target_username:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": "target_username is required",
            })
            return

        target_id = self.username_to_id.get(target_username)
        if not target_id:
            await self.send_to_player(player_id, {
                "type": "error",
                "message": f"Player '{target_username}' not found",
            })
            return

        target = self.players.get(target_id)
        if not target:
            return

        # Only show tradeable items publicly
        public_items = {
            k: v.to_dict() for k, v in target.inventory.items() if v.tradeable
        }

        await self.send_to_player(player_id, {
            "type": "player_inspect",
            "username": target.username,
            "tradeable_items": public_items,
            "item_count": len(target.inventory),
        })

    async def handle_message(self, player_id: str, websocket, raw_message: str):
        try:
            data = json.loads(raw_message)
        except json.JSONDecodeError:
            await websocket.send(json.dumps({
                "type": "error",
                "message": "Invalid JSON",
            }))
            return

        action = data.get("action")

        handlers = {
            "get_inventory": lambda: self.handle_get_inventory(player_id),
            "spawn_item": lambda: self.handle_spawn_item(player_id, data),
            "drop_item": lambda: self.handle_drop_item(player_id, data),
            "gift_item": lambda: self.handle_gift_item(player_id, data),
            "trade_request": lambda: self.handle_trade_request(player_id, data),
            "trade_add_item": lambda: self.handle_trade_add_item(player_id, data),
            "trade_remove_item": lambda: self.handle_trade_remove_item(player_id, data),
            "trade_set_gold": lambda: self.handle_trade_set_gold(player_id, data),
            "trade_accept": lambda: self.handle_trade_accept(player_id, data),
            "trade_cancel": lambda: self.handle_trade_cancel(player_id, data),
            "list_players": lambda: self.handle_list_players(player_id),
            "inspect_player": lambda: self.handle_inspect_player(player_id, data),
        }

        handler = handlers.get(action)
        if handler:
            await handler()
        else:
            await websocket.send(json.dumps({
                "type": "error",
                "message": f"Unknown action: {action}",
                "available_actions": list(handlers.keys()),
            }))

    async def handle_connection(self, websocket):
        player_id = None
        try:
            # Wait for login message
            login_msg = await websocket.recv()
            try:
                login_data = json.loads(login_msg)
            except json.JSONDecodeError:
                await websocket.send(json.dumps({
                    "type": "error",
                    "message": "Invalid JSON. Send: {\"action\": \"login\", \"username\": \"your_name\"}",
                }))
                return

            if login_data.get("action") != "login":
                await websocket.send(json.dumps({
                    "type": "error",
                    "message": "First message must be a login action",
                }))
                return

            player_id = await self.handle_login(websocket, login_data)
            if not player_id:
                return

            # Main message loop
            async for message in websocket:
                await self.handle_message(player_id, websocket, message)

        except websockets.exceptions.ConnectionClosed:
            logger.info(f"Connection closed for player {player_id}")
        except Exception as e:
            logger.error(f"Error handling connection for {player_id}: {e}", exc_info=True)
        finally:
            if player_id:
                await self.handle_disconnect(player_id)

    async def start(self):
        logger.info(f"Starting MMO Game Server on {self.host}:{self.port}")
        logger.info("Waiting for player connections...")

        async with websockets.serve(self.handle_connection, self.host, self.port):
            await asyncio.Future()  # Run forever


async def run_test_client(username: str, actions: list):
    """Test client for demonstration purposes."""
    import websockets as ws
    uri = "ws://localhost:8765"

    async with ws.connect(uri) as websocket:
        # Login
        await websocket.send(json.dumps({"action": "login", "username": username}))
        response = await websocket.recv()
        login_data = json.loads(response)
        print(f"[{username}] Login: {login_data.get('type')}")

        if login_data.get("type") != "login_success":
            print(f"[{username}] Login failed: {login_data}")
            return

        player_data = login_data["player"]
        print(f"[{username}] Gold: {player_data['gold']}, Items: {len(player_data['inventory'])}")

        for action_data in actions:
            await websocket.send(json.dumps(action_data))
            response = await websocket.recv()
            resp_data = json.loads(response)
            print(f"[{username}] {action_data.get('action')}: {resp_data.get('type')} - {resp_data.get('message', '')}")

            # Handle multi-response scenarios (trade notifications)
            try:
                while True:
                    extra = await asyncio.wait_for(websocket.recv(), timeout=0.5)
                    extra_data = json.loads(extra)
                    print(f"[{username}] (notification) {extra_data.get('type')}: {extra_data.get('message', '')}")
            except asyncio.TimeoutError:
                pass

            await asyncio.sleep(0.1)

        # Keep connection alive briefly for pending messages
        try:
            while True:
                extra = await asyncio.wait_for(websocket.recv(), timeout=1.0)
                extra_data = json.loads(extra)
                print(f"[{username}] (late notification) {extra_data.get('type')}: {extra_data.get('message', '')}")
        except asyncio.TimeoutError:
            pass

        print(f"[{username}] Done.")


